mapper.sql:
where c.deleted = ${@com.github.paicoding.forum.api.model.enums.YesOrNoEnum@NO.code}

    and c.id = #{req.commentId}


    and c.article_id = #{req.articleId}


    and c.user_id = #{req.userId}


    and a.title like concat('%', #{req.articleTitle}, '%')


    and u.user_name like concat('%', #{req.userName}, '%')


    and c.top_comment_id = 0


    and c.top_comment_id > 0

mapper.select:
select c.top_comment_id, count(*) as cnt
from comment c
         inner join comment tc on c.top_comment_id = tc.id
where c.article_id = #{articleId}
  and c.top_comment_id > 0
  and c.deleted = ${@com.github.paicoding.forum.api.model.enums.YesOrNoEnum@NO.code}
  and tc.deleted = ${@com.github.paicoding.forum.api.model.enums.YesOrNoEnum@NO.code}
group by c.top_comment_id
order by cnt desc limit 1

select c.id as commentId, c.article_id as articleId, a.title as articleTitle, c.user_id as userId, u.user_name as userName, u.photo as userAvatar, c.content as commentContent, c.parent_comment_id as parentCommentId, c.top_comment_id as topCommentId, pc.content as parentCommentContent, tc.content as topCommentContent, case when c.top_comment_id = 0 then 1 else 2 end as commentType, case when c.top_comment_id = 0 then ( select count(1) from comment sc where sc.top_comment_id = c.id and sc.deleted = ${@com.github.paicoding.forum.api.model.enums.YesOrNoEnum@NO.code} ) else 0 end as replyCount, c.highlight_info as highlightInfo, c.create_time as createTime, c.update_time as updateTime from comment c left join article a on c.article_id = a.id left join user_info u on c.user_id = u.user_id and u.deleted = ${@com.github.paicoding.forum.api.model.enums.YesOrNoEnum@NO.code} left join comment pc on c.parent_comment_id = pc.id left join comment tc on c.top_comment_id = tc.id
order by c.create_time desc, c.id desc
limit #{pageParam.offset}, #{pageParam.limit}
